887	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
888	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
889	    let mut best: Option<(usize, &FactId)> = None;
890	    for f in rhs {
891	        let d = edit_distance(name, &f.name);
892	        match best {
893	            Some((bd, _)) if d >= bd => {}
894	            _ => best = Some((d, f)),
895	        }
896	    }
897	    match best {
898	        Some((d, f)) if d <= 3 => Some(f),
899	        _ => None,
900	    }
901	}
