903	fn edit_distance(a: &str, b: &str) -> usize {
904	    let a: Vec<char> = a.chars().collect();
905	    let b: Vec<char> = b.chars().collect();
906	    let mut prev: Vec<usize> = (0..=b.len()).collect();
907	    let mut cur = vec![0usize; b.len() + 1];
908	    for i in 1..=a.len() {
909	        cur[0] = i;
910	        for j in 1..=b.len() {
911	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
912	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
913	        }
914	        std::mem::swap(&mut prev, &mut cur);
915	    }
916	    prev[b.len()]
917	}
